import java.util.*;

class BookMyShow {

    private int n, m;
    private List<Row> rows;

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        this.rows = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            rows.add(new Row(m));
        }
    }

    public int[] gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (rows.get(i).gather(k)) {
                return new int[]{i, rows.get(i).getStart()};
            }
        }
        return new int[]{};
    }

    public boolean scatter(int k, int maxRow) {
        int count = 0;
        for (int i = 0; i <= maxRow; i++) {
            count += rows.get(i).scatter(k - count);
            if (count >= k) {
                return true;
            }
        }
        return false;
    }

    private class Row {
        private int m;
        private int[] seats;

        public Row(int m) {
            this.m = m;
            this.seats = new int[m];
            Arrays.fill(seats, 0);
        }

        public boolean gather(int k) {
            for (int i = 0; i <= m - k; i++) {
                if (isAvailable(i, k)) {
                    book(i, k);
                    return true;
                }
            }
            return false;
        }

        public int getStart() {
            for (int i = 0; i < m; i++) {
                if (seats[i] == 1) {
                    return i - countBooked(i);
                }
            }
            return -1;
        }

        public int scatter(int k) {
            int count = 0;
            for (int i = 0; i < m && count < k; i++) {
                if (seats[i] == 0) {
                    seats[i] = 1;
                    count++;
                }
            }
            return count;
        }

        private boolean isAvailable(int start, int k) {
            for (int i = start; i < start + k; i++) {
                if (seats[i] == 1) {
                    return false;
                }
            }
            return true;
        }

        private void book(int start, int k) {
            for (int i = start; i < start + k; i++) {
                seats[i] = 1;
            }
        }

        private int countBooked(int index) {
            int count = 0;
            for (int i = index; i >= 0; i--) {
                if (seats[i] == 1) {
                    count++;
                } else {
                    break;
                }
            }
            return count;
        }
    }
}
